/**
 * Blur data URLs for image placeholders
 * These are tiny base64-encoded versions of the images for instant loading
 *
 * To generate a blur placeholder:
 * 1. Use a 10x10px version of the image
 * 2. Convert to base64: data:image/jpeg;base64,...
 */

// Simple gradient placeholder for portraits (dark theme compatible)
export const PORTRAIT_BLUR =
  'data:image/jpeg;base64,'

// Abstract background placeholder
export const ABSTRACT_BG_BLUR =
  'data:image/jpeg;base64,'

// Logo placeholder (simple dark)
export const LOGO_BLUR =
  'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAoAAAAKCAYAAACNMs+9AAAAFklEQVQoU2NkYGD4z0AEYBxVSF+FABJAAgGMwnmDAAAAAElFTkSuQmCC'

// Testimonial placeholder (person silhouette)
export const TESTIMONIAL_BLUR =
  'data:image/jpeg;base64,'

// Business/meeting image placeholder
export const BUSINESS_BLUR =
  'data:image/jpeg;base64,'

